B.a9=new A.o4(5,"tip")
B.O2=new A.Q(B.a9,"\u2708\ufe0f Exam Tip",'In multiple-choice questions, look for clues:\n\u2022 If the subject is a **thing** (not a person), passive is likely correct.\n\u2022 "\u2026\u2026\u2026\u2026 by the engine" \u2192 passive form needed.\n\u2022 Modal verbs + passive: **must be + past participle** is the most common pattern in aviation maintenance English.',null,null,null)
