B.OH=new A.Q(B.a7,"Tense signals when an action happens","In aviation English, choosing the right tense is critical. ATC uses **present simple** for permanent facts, **present continuous** for current actions, and **past simple** for completed events in reports.\n\nMixing tenses in checklists or reports is a common exam error.",null,null,null)
B.Kw=new A.nT(4,"tensesTimeline")
B.OI=new A.Q(B.eL,"Tenses on a timeline",null,null,B.Kw,null)
B.NL=new A.Q(B.B,"Simple vs. Continuous",'**Present Simple** \u2014 facts, routines, permanent states\n\u2192 "The ILS localizer **operates** on frequencies 108\u2013111.95 MHz."\n\n**Present Continuous** \u2014 actions happening now, temporary\n\u2192 "The aircraft **is climbing** through flight level 180."\n\n**Past Simple** \u2014 completed events (reports, logs)\n\u2192 "The crew **performed** the before-start checklist at 0612Z."\n\n**Past Continuous** \u2014 ongoing past action interrupted\n\u2192 "The aircraft **was taxiing** when the bird strike **occurred**."',null,null,null)
B.Jn=new A.aA("The aircraft is currently holding at ELVIN fix due to traffic congestion.","U\xe7ak, trafik yo\u011funlu\u011fu nedeniyle \u015fu anda ELVIN noktas\u0131nda bekleme yap\u0131yor.","is currently holding")
B.JP=new A.aA("The crew completed the after-landing checklist at 14:32 UTC.","Ekip ini\u015f sonras\u0131 kontrol listesini 14:32 UTC'de tamamlad\u0131.","completed")
B.Jt=new A.aA("ATIS information Bravo states that the active runway is 36L.","ATIS bilgisi Bravo, aktif pistin 36L oldu\u011funu belirtiyor.","states")
B.Sg=s([B.Jn,B.JP,B.Jt],t.l)
B.P1=new A.Q(B.a8,"Tense in Context",null,B.Sg,null,null)
B.Ov=new A.Q(B.a9,"\u2708\ufe0f Exam Tip","Time signal words give away the tense:\n\u2022 **now / currently / at the moment** \u2192 present continuous\n\u2022 **always / usually / every flight** \u2192 present simple\n\u2022 **at 14:32 / yesterday / last night** \u2192 past simple\n\u2022 **while / when / as** \u2192 look for two simultaneous past actions\n\nAviation logs and reports always use **past simple** \u2014 they record completed events.",null,null,null)
