B.Jm=new A.aA("All cabin crew must demonstrate the life vest donning procedure to passengers.","T\xfcm kabin ekibi yolculara can yele\u011fi giyinme prosed\xfcr\xfcn\xfc g\xf6stermelidir.","donning procedure")
