B.OC=new A.Q(B.a7,"Every METAR element has a precise meaning","Translation questions often ask you to interpret METAR or TAF codes and express them in plain English \u2014 or to identify the correct Turkish translation of a weather observation.\n\nEach element of a METAR appears in fixed order and has an exact meaning. Getting the order wrong or misinterpreting an abbreviation loses marks.",null,null,null)
B.P8=new A.Q(B.B,"\ud83c\udf26\ufe0f METAR Element Order","**METAR** LTBA **120850Z** **35015KT** **9999** **FEW030** **18/08** **Q1013** **NOSIG**\n\n1. Station ICAO code: LTBA (Istanbul)\n2. Date/Time: 12th at 08:50 UTC\n3. Wind: 350\xb0/15 knots\n4. Visibility: 9999 = 10km or more\n5. Cloud: FEW at 3,000ft AGL\n6. Temp/Dewpoint: 18\xb0C / 8\xb0C\n7. QNH: 1013 hPa\n8. Trend: NOSIG = no significant change",null,null,null)
B.O0=new A.Q(B.B,"\u2601\ufe0f Cloud Cover Codes",'**FEW** \u2014 1\u20132 oktas (1/8\u20132/8 coverage)\n**SCT (Scattered)** \u2014 3\u20134 oktas\n**BKN (Broken)** \u2014 5\u20137 oktas\n**OVC (Overcast)** \u2014 8 oktas (full coverage)\n**NSC** \u2014 No Significant Cloud\n**NCD** \u2014 No Cloud Detected (auto station)\n\nHeight is given in hundreds of feet AGL:\n"BKN015" = broken cloud at 1,500 feet AGL\n"OVC008" = overcast at 800 feet AGL',null,null,null)
B.Jj=new A.aA("OVC008 means overcast cloud at 800 feet above aerodrome level.","OVC008, ta\u015f\u0131t alan\u0131 seviyesinin 800 feet \xfczerinde tam kapal\u0131 bulut anlam\u0131na gelir.","overcast")
B.Jq=new A.aA("TSRA in a METAR indicates thunderstorm with rain in the vicinity.","METAR'daki TSRA, civarda \u015fim\u015fekli ya\u011f\u0131\u015f oldu\u011funu g\xf6sterir.","TSRA")
B.Kf=new A.aA("BECMG 0912 SCT020 means cloud will gradually become scattered at 2,000 feet between 09 and 12 UTC.","BECMG 0912 SCT020, bulutun 09\u201312 UTC aras\u0131nda kademeli olarak 2000 feet'te par\xe7al\u0131 hale gelece\u011fi anlam\u0131na gelir.","BECMG")
B.Ux=s([B.Jj,B.Jq,B.Kf],t.l)
B.Ns=new A.Q(B.a8,"Translation Examples",null,B.Ux,null,null)
B.NR=new A.Q(B.a9,"\u2708\ufe0f Exam Tip",'Most common METAR translation errors:\n\u2022 **9999** = 10km or more visibility (NOT "9,999 meters exactly")\n\u2022 **FEW030** = clouds at 3,000ft (add two zeros to METAR cloud height)\n\u2022 **18/08** = temperature 18\xb0C, dewpoint 8\xb0C (NOT "18 to 8")\n\u2022 **NOSIG** = no significant change expected in next 2 hours (NOT "no signal")\n\u2022 Wind "35015KT" = FROM 350\xb0, speed 15 knots (direction is WHERE wind comes FROM)',null,null,null)
