B.JL=new A.aA("The maintenance engineer said he would complete the inspection by 0600.","Bak\u0131m m\xfchendisi incelemeyi 06:00'ya kadar tamamlayaca\u011f\u0131n\u0131 s\xf6yledi.","would complete")
B.Qr=s([B.J3,B.K3,B.JL],t.l)
B.Pe=new A.Q(B.a8,"Aviation Reported Speech",null,B.Qr,null,null)
B.P7=new A.Q(B.a9,"\u2708\ufe0f Exam Tip",'Key reporting verbs and their prepositions:\n\u2022 said (that) \u2014 general statement\n\u2022 told + person + (that) \u2014 "told him/her"\n\u2022 reported (that) \u2014 formal/written report\n\u2022 informed + person + (that) \u2014 official notification\n\u2022 warned + person + (that/about) \u2014 hazard warning\n\nNo preposition after "said": \u2713 "said **that**" / \u2717 "said **to** him that"',null,null,null)
B.UB=s(["is","was","will be","has been"],t.s)
B.a19=new A.a5(-80,B.ac,180,"The pilot said that the engine \u2026\u2026\u2026\u2026 making unusual noises during the climb.",B.UB,1,B.z,null,null,null)
