B.ND=new A.Q(B.a1,"Practice Questions",'"Wet motoring the engine is necessary to test the fuel system. When an engine is wet motored, the two ignition systems are turned OFF and the starter is engaged to turn the HP rotor to 15%-20% N2. At N2 = 15%, the HP fuel shutoff valve control lever is moved to ON and the engine exhaust nozzle is carefully monitored for any sign of fuel."',null,null,B.SV)
B.W1=s([B.OS,B.Pz,B.PC,B.NS,B.Oi,B.ND],t.q)
B.MG=new A.ck("reading_2","Accident Report Analysis","\ud83d\udcd1",B.W1)
B.OJ=new A.Q(B.a7,"Low visibility operations demand precise language","CAT II and CAT III approaches are conducted in very low visibility using autoland systems. The phraseology, alerts, and callouts in these procedures are among the most precisely defined in aviation English.\n\nSentence completion questions in this area require exact knowledge of procedure terminology.",null,null,null)
B.NX=new A.Q(B.B,"\ud83c\udf2b\ufe0f ILS Categories","**CAT I** \u2014 DH \u2265200ft, RVR \u2265550m (standard ILS)\n**CAT II** \u2014 DH 100\u2013200ft, RVR \u2265300m (needs specific aircraft/crew cert)\n**CAT IIIA** \u2014 DH <100ft OR no DH, RVR \u2265200m\n**CAT IIIB** \u2014 DH <50ft OR no DH, RVR 50\u2013200m\n**CAT IIIC** \u2014 No DH, No RVR limit (still not in service)\n\n**LVP** \u2014 Low Visibility Procedures (activated by airport when RVR <600m)\n**LVT** \u2014 Low Visibility Takeoff",null,null,null)
B.Na=new A.Q(B.B,"\ud83d\udce2 CAT III Callouts",'Standard CAT III approach callouts (in order):\n1. "**Localizer alive**" \u2014 ILS localizer captured\n2. "**Glide slope alive**" \u2014 vertical guidance captured\n3. "**Land 3**" \u2014 autoland mode confirmed (A320 family)\n4. "**1,000 feet**" \u2014 standard check altitude\n5. "**500 feet**" \u2014 stability check\n6. "**100 feet**" \u2014 visual or go-around decision\n7. "**50, 40, 30, 20, 10**" \u2014 radio altimeter callouts\n8. "**Touchdown**" \u2192 "**Decelerate**" \u2192 "**Vacate**"',null,null,null)
B.Je=new A.aA("During LVP, ground movement must be strictly controlled to prevent runway incursion.","LVP s\u0131ras\u0131nda pist ihlalini \xf6nlemek i\xe7in yer hareketi kesinlikle kontrol edilmelidir.","LVP")
B.IZ=new A.aA("At Decision Height, if the required visual reference is not established, a go-around must be executed.","Karar \u0130rtifas\u0131nda, gerekli g\xf6rsel referans sa\u011flanamazsa t\u0131rman\u0131\u015f prosed\xfcr\xfc uygulanmal\u0131d\u0131r.","Decision Height")
B.Si=s([B.Je,B.IZ],t.l)
B.O6=new A.Q(B.a8,"CAT III Completion Examples",null,B.Si,null,null)
B.P_=new A.Q(B.a9,"\u2708\ufe0f Exam Tip",'CAT II/III key distinctions for exams:\n\u2022 **DH** = Decision Height (radio altimeter based, CAT II/III)\n\u2022 **DA** = Decision Altitude (barometric, CAT I)\n\u2022 **RVR** = Runway Visual Range (measured by transmissometers)\n\u2022 A CAT IIIB approach may be conducted with **no Decision Height** if auto-rollout/auto-brake available\n\u2022 LVP does NOT cancel low-visibility departures automatically \u2014 there are separate LVT minima\n\u2022 "Required visual reference" for CAT III is **less** than for CAT I (may be just runway edge lights)',null,null,null)
